    // fshl(X, 0, Y) --> shl X, Y (when Y is known to be in [0, BitWidth))
    // fshl(X, 0, Y) --> shl X, (Y & (BitWidth-1)) (when Y might be >= BitWidth)
    // fshl(X, undef, Y) --> same as above
    Value *ShAmt = II->getArgOperand(2);
    if (match(Op1, m_ZeroInt()) || match(Op1, m_Undef())) {
      // Check if the shift amount is known to be in the valid range [0, BitWidth).
      ConstantRange ValidRange(APInt(BitWidth, 0), APInt(BitWidth, BitWidth));
      ConstantRange ShAmtRange =
          computeConstantRangeIncludingKnownBits(ShAmt, /*ForSigned=*/false,
                                                 SQ.getWithInstruction(II));
      if (ValidRange.contains(ShAmtRange)) {
        // Safe to use shl directly without masking.
        return BinaryOperator::CreateShl(Op0, ShAmt);
      }
      // Need to mask the shift amount to ensure it's in valid range.
      Value *Mask = ConstantInt::get(Ty, BitWidth - 1);
      Value *MaskedShAmt = Builder.CreateAnd(ShAmt, Mask);
      return BinaryOperator::CreateShl(Op0, MaskedShAmt);
    }

    // fshl(0, X, Y) --> lshr X, (BW-Y)
    // fshl(undef, X, Y) --> lshr X, (BW-Y)
    if (match(Op0, m_ZeroInt()) || match(Op0, m_Undef()))
      return BinaryOperator::CreateLShr(Op1,
                                        BinaryOperator::CreateSub(ConstantInt::get(Ty, BitWidth),
                                                                  II->getArgOperand(2)));
CODEEOF
